+    _ = qjs.JS_SetPropertyStr(ctx, obj, "atimeMs", qjs.JS_NewInt64(ctx, atime_ms));
+    _ = qjs.JS_SetPropertyStr(ctx, obj, "ctimeMs", qjs.JS_NewInt64(ctx, ctime_ms));
