+    while (iter.next() catch null) |entry| {
+        const name_val = qjs.JS_NewStringLen(ctx, entry.name.ptr, entry.name.len);
+        _ = qjs.JS_SetPropertyUint32(ctx, arr, idx, name_val);
+        idx += 1;
+    }
