+#define MAX_TIME 10
+
+static int timeout_interrupt_handler(JSRuntime *rt, void *opaque)
+{
+    int *time = (int *)opaque;
+    if (*time <= MAX_TIME)
+        *time += 1;
+    return *time > MAX_TIME;
+}
+
+static void sync_call(void)
+{
+    static const char code[] =
+"(function() { \
+    try { \
+        while (true) {} \
+    } catch (e) {} \
+})();";
+
+    JSRuntime *rt = JS_NewRuntime();
+    JSContext *ctx = JS_NewContext(rt);
+    int time = 0;
+    JS_SetInterruptHandler(rt, timeout_interrupt_handler, &time);
+    JSValue ret = eval(ctx, code);
+    assert(time > MAX_TIME);
+    assert(JS_IsException(ret));
+    JS_FreeValue(ctx, ret);
+    assert(JS_HasException(ctx));
+    JSValue e = JS_GetException(ctx);
+    assert(JS_IsUncatchableError(e));
+    JS_FreeValue(ctx, e);
+    JS_FreeContext(ctx);
+    JS_FreeRuntime(rt);
+}
+
+static void async_call(void)
+{
+    static const char code[] =
+"(async function() { \
+    const loop = async () => { \
+        await Promise.resolve(); \
+        while (true) {} \
+    }; \
+    await loop().catch(() => {}); \
+})();";
+
+    JSRuntime *rt = JS_NewRuntime();
+    JSContext *ctx = JS_NewContext(rt);
+    int time = 0;
+    JS_SetInterruptHandler(rt, timeout_interrupt_handler, &time);
+    JSValue ret = eval(ctx, code);
+    assert(!JS_IsException(ret));
+    JS_FreeValue(ctx, ret);
+    assert(JS_IsJobPending(rt));
+    int r = 0;
+    while (JS_IsJobPending(rt)) {
+        r = JS_ExecutePendingJob(rt, &ctx);
+    }
+    assert(time > MAX_TIME);
+    assert(r == -1);
+    assert(JS_HasException(ctx));
+    JSValue e = JS_GetException(ctx);
+    assert(JS_IsUncatchableError(e));
+    JS_FreeValue(ctx, e);
+    JS_FreeContext(ctx);
+    JS_FreeRuntime(rt);
+}
