+static JSValue save_value(JSContext *ctx, JSValueConst this_val,
+                          int argc, JSValueConst *argv)
+{
+    assert(argc == 1);
+    JSValue *p = (JSValue *)JS_GetContextOpaque(ctx);
+    *p = JS_DupValue(ctx, argv[0]);
